import 'package:flutter/material.dart';import '../core/api_client.dart';class RegisterScreen extends StatefulWidget{const RegisterScreen({super.key});@override State<RegisterScreen> createState()=>_R();}class _R extends State<RegisterScreen>{final u=TextEditingController(),e=TextEditingController(),p=TextEditingController(),hp=TextEditingController();Future<void>reg()async{final r=await ApiClient.post('register.php',body:{'username':u.text,'email':e.text,'phone':hp.text,'password':p.text});if(mounted){ScaffoldMessenger.of(context).showSnackBar(SnackBar(content:Text('${r['message']}')));if(r['status']=='success')Navigator.pop(context);}}@override Widget build(BuildContext c)=>Scaffold(appBar:AppBar(title:const Text('Register')),body:ListView(padding:const EdgeInsets.all(20),children:[TextField(controller:u,decoration:const InputDecoration(labelText:'Nama')),TextField(controller:e,decoration:const InputDecoration(labelText:'Email')),TextField(controller:hp,decoration:const InputDecoration(labelText:'HP')),TextField(controller:p,obscureText:true,decoration:const InputDecoration(labelText:'Password')),const SizedBox(height:20),FilledButton(onPressed:reg,child:const Text('Daftar'))]));}
